(32, 'Hero Section', 'hero', '{\"hero_title\":\"Plateforme d\'investissement Hyip pour gagner de l\'argent en ligne\",\"hero_content\":\"Nous avons consid\\u00e9r\\u00e9 nos solutions pour soutenir chaque \\u00e9tape de votre croissance et obtenir le service potentiel.\",\"hero_button1_icon\":\"nfc\",\"hero_button1_level\":\"Faire des investissements\",\"hero_button1_url\":\"https:\\/\\/hyiprio.tdevs.co\\/register\",\"hero_button1_target\":\"_self\",\"hero_button2_icon\":\"move-right\",\"hero_button2_lavel\":\"Comment \\u00e7a fonctionne\",\"hero_button2_url\":\"https:\\/\\/hyiprio.tdevs.co\\/how-it-works\",\"hero_button2_target\":\"_self\",\"hero_right_img\":\"global\\/images\\/6o9uYYN51THTuXUAEh17.png\",\"hero_right_top_img\":\"global\\/images\\/lLJT3xQhVp4mkOyxtRC3.png\",\"company_slogan\":\"\"}', 1, '2023-07-18 16:53:17', '2023-10-19 10:28:22', 1, 'fr'),
