INSERT INTO `risk_profile_tags` (`id`, `name`, `desc`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Suspicious', 'Unusual trading patterns or activities that could indicate potential market manipulation, money laundering, or other illicit activities.', 1, '2024-01-24 15:29:38', '2024-01-27 06:21:20'),
(2, 'HFT & Arbitrage', 'Clients engaged in high-frequency trading and arbitrage strategies. These clients typically require more bandwidth and resources due to the high volume and speed of their trades.', 1, '2024-01-27 06:21:39', '2024-01-27 06:21:39'),
(3, 'High Risk Trader', 'Consistently take significant risks in their trading strategy, such as using high leverage, large positions relative to their account size, or trading volatile instruments.', 1, '2024-01-27 06:21:58', '2024-01-27 06:21:58'),
(4, 'Under Investigation', 'Currently being investigated for any potential breaches of trading policies, regulations, or suspicious activities.', 1, '2024-01-27 06:22:16', '2024-01-27 06:22:16'),
(5, 'Under Audit', 'Undergoing a routine or triggered financial audit to ensure compliance with regulatory standards and internal policies.', 1, '2024-01-27 06:22:33', '2024-01-27 06:22:33'),
(6, 'Under Review', 'Being reviewed due to performance issues, risk management concerns, or as part of a regular assessment process.', 1, '2024-01-27 06:22:49', '2024-01-27 06:22:49'),
(7, 'Fraudulent Activites', 'Irregularities or suspicious activities related to funds transfers, either incoming or outgoing, which might indicate fraudulent activities.', 1, '2024-01-27 06:23:08', '2024-01-27 06:23:08'),
(8, 'Low Activity', 'Minimal trading activity over a significant period, which could indicate a dormant or less engaged client.', 1, '2024-01-27 06:23:23', '2024-01-27 06:23:23'),
(9, 'Scalper', 'Scalping strategies, characterized by making a large number of small profits on minor price changes.', 1, '2024-01-27 06:23:39', '2024-01-27 06:23:39'),
(10, 'News Trader', 'Primarily trade based on news events, which often involves higher risk due to market volatility.', 1, '2024-01-27 06:24:10', '2024-01-27 06:24:10'),
(11, 'Margin Call', 'Received a margin call, indicating they are at risk of falling below the minimum required margin.', 1, '2024-01-27 06:24:28', '2024-01-27 06:24:28'),
(12, 'Frequent Transactions', 'High frequency of fund movements, which might necessitate closer monitoring.', 1, '2024-01-27 06:24:49', '2024-01-27 06:24:49'),
(13, 'VIP Client', 'High-value clients who may require personalized services or account management.', 1, '2024-01-27 06:25:13', '2024-01-27 06:25:13'),
(14, 'New Client', 'New to the platform, potentially requiring more guidance or monitoring as they familiarize themselves with trading.', 1, '2024-01-27 06:25:32', '2024-01-27 06:25:32'),
(15, 'Consistently Profitable', 'Demonstrated a consistent ability to make profitable trades over a significant period.', 1, '2024-01-27 06:25:58', '2024-01-27 06:25:58');
