INSERT INTO `sms_templates` (`id`, `name`, `code`, `for`, `message_body`, `short_codes`, `status`, `created_at`, `updated_at`) VALUES
(1, 'New User', 'new_user', 'Admin', 'Thanks for joining us  [[full_name]]<br />\r\n [[message]]', '[\"[[full_name]]\",\"[[message]]\"]', 1, NULL, '2023-05-21 09:17:51'),
(2, 'User Investment\r\n', 'user_investment', 'User', 'Hello!<br />\r\n[[txn]]. \'Successfully Investment<br />\r\n[[plan_name]]<br />\r\n[[invest_amount]]', '[\"[[full_name]]\",\"[[txn]]\",\"[[plan_name]]\",\"[[invest_amount]]\",\"[[site_title]]\"]', 1, NULL, NULL),
(3, 'User Account Disabled', 'user_account_disabled', 'Admin', 'Your account is disabled for a serious cause. Sorry! you\'re unable to use your account again.', NULL, 1, NULL, NULL),
(4, 'Manual Deposit request', 'manual_deposit_request', 'User', 'The manual deposit request details:<br />\r\n[[txn]]<br />\r\n[[gateway_name]]<br />\r\n[[deposit_amount]]', '[\"[[full_name]]\",\"[[txn]]\",\"[[gateway_name]]\",\"[[deposit_amount]]\",\"[[site_title]]\"]', 1, NULL, NULL),
(5, 'Withdraw Request', 'withdraw_request ', 'User', 'Withdraw Request details:<br />\r\n[[txn]]<br />\r\n[[method_name]]<br />\r\n[[withdraw_amount]]', '[\"[[full_name]]\",\"[[txn]]\",\"[[method_name]]\",\"[[withdraw_amount]]\",\"[[site_title]]\"]', 1, NULL, NULL),
(6, 'KYC Request', 'kyc_request', 'User', 'Thanks for joining our platform! ---  [[site_title]]<br />\r\n<br />\r\n[[full_name]]<br />\r\n[[email]]<br />\r\n<br />\r\nAs a member of our platform, you can mange your account, buy or sell cryptocurrency, invest and earn profits.<br />\r\n<br />\r\nFind out more about in - [[site_url]]', '[\"[[site_url]]\",\"[[site_title]]\",\"[[full_name]]\",\"[[email]]\",\"[[kyc_type]]\"]', 1, NULL, NULL),
(7, 'KYC Action', 'kyc_action', 'User', 'Thanks for joining our platform! ---  [[site_title]]<br />\r\n<br />\r\n[[message]]<br />\r\n[[full_name]]<br />\r\n[[email]]<br />\r\n<br />\r\nAs a member of our platform, you can mange your account, buy or sell cryptocurrency, invest and earn profits.<br />\r\n<br />\r\nFind out more about in - [[site_url]]', '[\"[[site_url]]\",\"[[site_title]]\",\"[[full_name]]\",\"[[email]]\",\"[[message]]\",\"[[kyc_type]]\"]', 1, NULL, NULL),
(8, 'Invest ROI', 'invest_roi', 'User', 'Hello!<br />\r\n[[txn]]. \'Successfully Investment<br />\r\n[[plan_name]]<br />\r\n[[invest_amount]]<br />\r\n[[roi]]', '[\"[[full_name]]\",\"[[txn]]\",\"[[plan_name]]\",\"[[invest_amount]]\",\"[[roi]]\",\"[[site_title]]\",\"[[site_url]]\"]', 1, NULL, NULL),
(9, 'Investment End', 'investment_end', 'User', 'Hello!<br />\r\n[[txn]]. \'Successfully Investment End<br />\r\n[[plan_name]]<br />\r\n[[invest_amount]]', '[\"[[full_name]]\",\"[[plan_name]]\",\"[[invest_amount]]\",\"[[site_title]]\",\"[[site_url]]\"]', 1, NULL, NULL),
(10, 'Withdraw Request Action', 'withdraw_request_user', 'User', 'Withdraw Request details:<br />\r\n[[message]]<br />\r\n[[txn]]<br />\r\n[[method_name]]<br />\r\n[[withdraw_amount]]<br />\r\n[[status]]', '[\"[[full_name]]\",\"[[message]]\",\"[[txn]]\",\"[[method_name]]\",\"[[withdraw_amount]]\",\"[[site_title]]\",\"[[site_url]]\",\"[[status]]\"]', 1, NULL, NULL),
(11, 'Manual Deposit request Action', 'user_manual_deposit_request', 'User', 'The manual deposit request details:<br />\r\n[[message]]\r\n[[txn]]<br />\r\n[[gateway_name]]<br />\r\n[[deposit_amount]]\r\n[[status]]\r\n', '[\"[[full_name]]\",\"[[message]]\",\"[[txn]]\",\"[[gateway_name]]\",\"[[deposit_amount]]\",\"[[site_title]]\",\"[[site_url]]\",\"[[status]]\"]', 1, NULL, NULL);
